patch:
diff --git a/llvm/lib/Transforms/Scalar/CorrelatedValuePropagation.cpp b/llvm/lib/Transforms/Scalar/CorrelatedValuePropagation.cpp
index 5226aeb66f65..fb6b7b9383d0 100644
--- a/llvm/lib/Transforms/Scalar/CorrelatedValuePropagation.cpp
+++ b/llvm/lib/Transforms/Scalar/CorrelatedValuePropagation.cpp
@@ -412,10 +412,45 @@ static bool processSwitch(SwitchInst *I, LazyValueInfo *LVI,

     if (ReachableCaseCount > 1 && !SI->defaultDestUnreachable()) {
       BasicBlock *DefaultDest = SI->getDefaultDest();
-      ConstantRange CR = LVI->getConstantRangeAtUse(I->getOperandUse(0),
-                                                    /*UndefAllowed*/ false);
-      // The default dest is unreachable if all cases are covered.
-      if (!CR.isSizeLargerThan(ReachableCaseCount)) {
+
+      bool DefaultUnreachable = false;
+      // If there are multiple predecessors (e.g. loops), use a strict per-edge
+      // proof to avoid miscompiles. Otherwise, fall back to the original
+      // ConstantRange coverage heuristic for single-predecessor blocks.
+      if (!pred_empty(BB) && !BB->hasNPredecessors(1)) {
+        // Only use per-edge reasoning if the condition is a live-in to BB.
+        // LVI's getPredicateOnEdge is not valid if Cond is defined in BB.
+        if (isa<Argument>(Cond) || (isa<Instruction>(Cond) &&
+                                    cast<Instruction>(Cond)->getParent() != BB)) {
+          DefaultUnreachable = true;
+          for (BasicBlock *Pred : predecessors(BB)) {
+            bool SomeCaseAlwaysFires = false;
+            for (auto CI2 = SI->case_begin(), CE2 = SI->case_end(); CI2 != CE2; ++CI2) {
+              ConstantInt *CaseVal = CI2->getCaseValue();
+              auto *ResOnEdge = dyn_cast_or_null<ConstantInt>(
+                  LVI->getPredicateOnEdge(ICmpInst::ICMP_EQ, Cond, CaseVal,
+                                          Pred, BB, I));
+              if (ResOnEdge && ResOnEdge->isOne()) {
+                SomeCaseAlwaysFires = true;
+                break;
+              }
+            }
+            if (!SomeCaseAlwaysFires) {
+              DefaultUnreachable = false;
+              break;
+            }
+          }
+        } else {
+          DefaultUnreachable = false; // Cannot safely prove per-edge.
+        }
+      } else {
+        ConstantRange CR = LVI->getConstantRangeAtUse(I->getOperandUse(0),
+                                                      /*UndefAllowed*/ false);
+        // The default dest is unreachable if all cases are covered.
+        DefaultUnreachable = !CR.isSizeLargerThan(ReachableCaseCount);
+      }
+
+      if (DefaultUnreachable) {
         BasicBlock *NewUnreachableBB =
             BasicBlock::Create(BB->getContext(), "default.unreachable",
                                BB->getParent(), DefaultDest);

